FROM filtered_rail_cal LEFT OUTER JOIN dbo.fact_engine_idling_episode ON filtered_rail_cal.start_date IS NOT NULL AND filtered_rail_cal.end_date IS NOT NULL AND CAST(dbo.fact_engine_idling_episode.episode_start_time AS DATE) BETWEEN filtered_rail_cal.start_date AND filtered_rail_cal.end_date OR filtered_rail_cal.start_date IS NULL AND filtered_rail_cal.end_date IS NULL AND dbo.fact_engine_idling_episode.period_sort_id = filtered_rail_cal.period_sort_id 

