ng_episode.episode_duration_minutes >= 3 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 4) THEN '3 - 4' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 4 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 5) THEN '4 - 5' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 5 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 6) THEN '5 - 6' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 6 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 7) THEN '6 - 7' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 7 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 8) THEN '7 - 8' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 8 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 9) THEN '8 - 9' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 9 AND dbo.fact_engine_idling_episode.episode_duration_minutes <= 10) THEN '9 - 10' WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes > 10) THEN '> 10 minutes' END, CASE WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes < 1) THEN 1 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 1 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 2) THEN 2 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 2 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 3) THEN 3 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 3 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 4) THEN 4 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 4 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 5) THEN 5 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 5 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 6) THEN 6 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 6 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 7) THEN 7 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 7 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 8) THEN 8 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 8 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 9) THEN 9 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 9 AND dbo.fact_engine_idling_episode.episode_duration_minutes <= 10) THEN 10 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes > 10) THEN 11 END ORDER BY CASE WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes < 1) THEN 1 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 1 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 2) THEN 2 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 2 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 3) THEN 3 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 3 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 4) THEN 4 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 4 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 5) THEN 5 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 5 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 6) THEN 6 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 6 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 7) THEN 7 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 7 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 8) THEN 8 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 8 AND dbo.fact_engine_idling_episode.episode_duration_minutes < 9) THEN 9 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes >= 9 AND dbo.fact_engine_idling_episode.episode_duration_minutes <= 10) THEN 10 WHEN (dbo.fact_engine_idling_episode.episode_duration_minutes > 10) THEN 11 END